def read_until_with_timeout(session: FirmwareSession, predicate, timeout_s: float = 2.0) -> list[str]:
    """Read lines until predicate matches, with timeout. Skips BOOTED and startup messages."""
    import time
    deadline = time.monotonic() + timeout_s
    lines = []
    while time.monotonic() < deadline:
        new_lines = session.read_lines(timeout_s=0.1)
        if not new_lines:
            break
        # Filter out BOOTED and startup messages, keep only relevant lines
        filtered = [line for line in new_lines if "DBG BOOTED" not in line and "main_task:" not in line]
        lines.extend(filtered)
        for l in filtered:
            if predicate(l):
                return lines
    raise TimeoutError(f"Predicate was not satisfied within {timeout_s:.2f} s")
